{
  "title": "RefCell का व्यवहार",
  "group": "RefCells",
  "options": [
    {
      "text": "आउटपुट: 42",
      "hint": "क्या हम एक साथ दो mutable borrows ले सकते हैं?"
    },
    {
      "text": "रनटाइम पैनिक: RefCell already borrowed"
    },
    {
      "text": "कंपाइलेशन एरर",
      "hint": "RefCell चेकिंग को रनटाइम पर शिफ्ट कर देता है"
    },
    {
      "text": "रनटाइम पैनिक: अलग मैसेज",
      "hint": "त्रुटि विशेष रूप से borrowing का उल्लेख करती है"
    }
  ],
  "questionProse": [
    "इस कोड को चलाने पर क्या होगा?"
  ],
  "explanationProse": [
    "RefCell इंटीरियर म्यूटेबिलिटी प्रदान करता है, लेकिन यह रनटाइम पर Rust के borrowing नियमों को लागू करता रहता है:",
    "मुख्य अवधारणाएँ:\n      1. RefCell borrowing चेक को रनटाइम पर शिफ्ट कर देता है\n      2. नियमों का उल्लंघन होने पर पैनिक हो सकता है\n      3. इंटीरियर म्यूटेबिलिटी पैटर्न के लिए उपयोगी\n\n      सामान्य उपयोग के मामले:\n      - टेस्ट में मॉक ऑब्जेक्ट्स\n      - सेल्फ-रेफरेंशियल स्ट्रक्चर्स को इम्प्लीमेंट करना\n      - जब आपको शेयर्ड रेफरेंस के पीछे डेटा को म्यूटेट करना हो\n      \n      बेस्ट प्रैक्टिसेज़:\n      1. जहाँ तक संभव हो, कंपाइल-टाइम borrowing को प्राथमिकता दें\n      2. RefCell borrows को छोटे स्कोप में रखें\n      3. borrows को स्पष्ट रूप से समाप्त करने के लिए drop() का उपयोग करने पर विचार करें\n      4. जब आपको इंटीरियर म्यूटेबिलिटी की आवश्यकता हो, तभी RefCell का उपयोग करें"
  ]
}
